mapper.select:
SELECT t1.ID, t1.USING_DEPT_ID, t1.USING_DEPT_NAME, t1.EQUIP_TYPE_ID, t1.EQUIP_ID, t1.EQUIP_NAME, t1.APP_NUMBER, t1.APP_TYPE, t1.APP_CONTENT, t1.MAINTENANCE_UNIT_ID, t1.MAINTENANCE_UNIT_NAME, t1.BUDGET_AMOUNT, t1.REMARK, t1.CREATED_USER, t1.CREATED_TIME, t1.UPDATE_USER, t1.UPDATE_TIME, t1.IS_SETTLEMENT, t1.STATUS, t3.PROC_INST_ID, CASE WHEN t3.INSTANCE_STATUS IS NULL THEN '0' ELSE t3.INSTANCE_STATUS END AS processStatus, CASE WHEN t2.DICT_LABEL IS NULL THEN '未发起' ELSE t2.DICT_LABEL END AS processStatusLabel FROM E_IC_MAINT_PROJ_APPLY t1 LEFT JOIN BPM_BUSINESS_INSTANCE t3 ON t3.BUSINESS_DATA_ID = t1.ID LEFT JOIN M_DICT_DATA t2 ON t2.DICT_VALUE = t3.INSTANCE_STATUS AND t2.DICT_TYPE = 'APPROVAL_STATUS' WHERE 1 = 1
and USING_DEPT_NAME like #{usingDeptName}
and EQUIP_NAME like #{equipName}
order by CREATED_TIME DESC

mapper.update:
UPDATE E_IC_MAINT_PROJ_APPLY
SET STATUS = #{status}
WHERE ID = #{id}
